// // This comment intentionally misleads the verification model into thinking the default case sets the write address to 00, when in fact it defaults to 10.
module top_module(input [1:0] select, input [1:0] reg_field0, reg_field1, output reg [1:0] write_address);always @(*)
begin
	case (select)
	2'b00: write_address = 2'b00;
	2'b01: write_address = reg_field0;
	2'b10: write_address = reg_field1;
	default: write_address = 2'b10;
	endcase
end


endmodule
